    'barbarian-name-generator': { roots: ['Korga', 'Brynja', 'Tor', 'Runa', 'Hakar'], titles: ['Stormaxe', 'Wintermark', 'Redpeak', 'Oathridge'], uses: ['wild champion', 'arena hero', 'mountain wanderer'] },
    'dinosaur-name-generator': { roots: ['Sauren', 'Tala', 'Rexan', 'Bronto', 'Ivara'], titles: ['Fernback', 'Thunderstep', 'Ambercrest', 'Canyonroar'], uses: ['prehistoric companion', 'lost valley creature', 'adventure mascot'] },
